import React from 'react';
import './App.css';

import Welcome from './apps/welcome/page/welcome/welcome';
import DontBreakChain from './apps/studio/dontbreakchain/page/dontbreakchain/dontbreakchain';

function App() {
  let url = new URL(window.location.href);
  let p = url.searchParams.get("p");

  let content = null;
  switch (p) {
    case "studio_dontbreakchain":
      content = (<DontBreakChain />);
      break;
  
    default:
        content = (<Welcome />);
      break;
  }

  return (
    <div className="App">
      <div className="Curtain">
        {content}
      </div>
    </div>
  );
}

export default App;
